# 输入获取
cards = input().split()


def mapToNum(card):
    if card == "J":
        return 11
    elif card == "Q":
        return 12
    elif card == "K":
        return 13
    elif card == "A":
        return 14
    elif card == "2":
        return 16
    else:
        return int(card)


# 算法入口
def getResult():
    cards.sort(key=lambda x: mapToNum(x))

    straights = [[cards[0]]]

    for i in range(1, len(cards)):
        card = cards[i]

        flag = True

        for straight in straights:
            if mapToNum(card) - mapToNum(straight[-1]) == 1:
                straight.append(card)
                flag = False
                break

        if flag:
            straights.append([card])

    straights = list(filter(lambda x: len(x) >= 5, straights))

    if len(straights) == 0:
        print("No")
        return

    straights.sort(key=lambda x: mapToNum(x[0]))

    for straight in straights:
        print(" ".join(straight))


# 调用算法
getResult()
